    'Raleway-ExtraLight.ttf' = 'https://github.com/impallari/Raleway/raw/master/fonts/ttf/Raleway-ExtraLight.ttf'
    'Raleway-Medium.ttf'     = 'https://github.com/impallari/Raleway/raw/master/fonts/ttf/Raleway-Medium.ttf'
}
foreach \(\\$name in \\$urls.Keys\) {
    \\$path = \\"\\$dest/\\$name\\"
    try {
        Invoke-WebRequest -Uri \\$urls[\\$name] -OutFile \\$path -TimeoutSec 30
        \\$size = \(Get-Item \\$path\).Length
        Write-Host \\"OK: \\$name \(\\$size bytes\)\\"
    } catch {
        Write-Host \\"FAIL: \\$name - \\$_\\"
    }
}
")
